// UART Transmitter - 9600 baud
module RefModule(
    input wire clk,
    input wire load,
    input wire [7:0] data_in,
    output reg [7:0] data_out
);

always @(posedge clk) begin
    if (load) begin
        data_out <= data_in;
    end else begin
        data_out <= {1'b0, data_out[7:1]};
    end
end

endmodule
